  page.on("pageerror", (err) => logs.push(`[pageerror] ${err.message}`));

  await page.goto("https://comp.designflow.app/", { waitUntil: "networkidle" });
  const title = await page.title();
  const stamp = await page.locator("#build-stamp").textContent().catch(() => null);

  await page.goto("https://comp.designflow.app/profile", { waitUntil: "networkidle" });
  const profileUrl = page.url();
  const bodyText = await page.locator("body").innerText().catch(() => "");
  const screenshotPath = "/home/ai/compshop/playwright-profile-check.png";
  await page.screenshot({ path: screenshotPath, fullPage: true });

  console.log(JSON.stringify({
    title,
    stamp,
    profileUrl,
    bodyExcerpt: bodyText.slice(0, 1000),
    consoleLogs: logs.slice(-20),
    screenshotPath,
  }, null, 2));
});
